def load_sheet(sheet_id):
    url = f"https://docs.google.com/spreadsheets/d/{sheet_id}/export?format=csv"
    try:
        r = requests.get(url, timeout=10)
        r.raise_for_status()
        df = pd.read_csv(StringIO(r.text))
        df.columns = df.columns.str.strip()
        return df
    except:
        return pd.DataFrame()

@st.cache_data(ttl=300)
def load_all():
    return load_sheet(HH_ID), load_sheet(SC_ID)

hh_raw, sc_raw = load_all()

# ── PROCESS SCHOOL ────────────────────────────────────────────
def process_school(df):
    if df.empty:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame()
    df = df.copy()
    col_map = {}
    for c in df.columns:
        cl = c.lower()
        if 'date' in cl:      col_map[c] = 'Date'
        elif 'time' in cl:    col_map[c] = 'Time Slot'
        elif 'class' in cl:   col_map[c] = 'Class'
        elif 'fan' in cl:     col_map[c] = 'Fans ON'
        elif 'light' in cl:   col_map[c] = 'Lights ON'
        elif 'phase' in cl:   col_map[c] = 'Phase'
        elif 'note' in cl:    col_map[c] = 'Notes'
    df = df.rename(columns=col_map)
    for col in ['Fans ON','Lights ON']:
        if col in df.columns:
            df[col] = pd.to_numeric(df[col], errors='coerce')
    if 'Date' in df.columns:
        df['Date'] = pd.to_datetime(df['Date'], errors='coerce')
    df = df.dropna(subset=['Fans ON','Lights ON'])
    group_cols = [c for c in ['Date','Class','Phase'] if c in df.columns]
    daily = df.groupby(group_cols).agg(
        avg_fans=('Fans ON','mean'),
        avg_lights=('Lights ON','mean'),
        slots=('Time Slot','count')
    ).reset_index()
    daily['avg_devices'] = daily['avg_fans'] + daily['avg_lights']
    baseline = daily[daily['Phase']=='Baseline']
    intervention = daily[daily['Phase']=='Intervention']
    b_avg = baseline.groupby('Class')['avg_devices'].mean()
    summary = pd.DataFrame({'baseline_avg': b_avg})
    if not intervention.empty:
        i_avg = intervention.groupby('Class')['avg_devices'].mean()
        summary['intervention_avg'] = i_avg
        summary['efficiency_pct'] = ((summary['baseline_avg'] - summary['intervention_avg']) / summary['baseline_avg'] * 100).round(1)
        mx = summary['efficiency_pct'].max()
        summary['score'] = (summary['efficiency_pct'] / mx * 100).round(0).astype(int) if mx > 0 else 0
        summary['rank'] = summary['efficiency_pct'].rank(ascending=False).astype(int)
    else:
        summary['intervention_avg'] = None
        summary['efficiency_pct'] = None
        summary['score'] = None
        summary['rank'] = None
    return daily, summary.reset_index(), df

# ── PROCESS HOUSEHOLD ─────────────────────────────────────────
def process_household(df):
    if df.empty:
        return pd.DataFrame(), pd.DataFrame()
    df = df.copy()
    col_map = {}
    for c in df.columns:
        cl = c.lower()
        if 'date' in cl:         col_map[c] = 'Date'
        elif 'household' in cl:  col_map[c] = 'Household ID'
        elif 'meter' in cl:      col_map[c] = 'Meter Reading'
        elif 'phase' in cl:      col_map[c] = 'Phase'
        elif 'note' in cl:       col_map[c] = 'Notes'
    df = df.rename(columns=col_map)
    if 'Meter Reading' in df.columns:
        df['Meter Reading'] = pd.to_numeric(df['Meter Reading'], errors='coerce')
    if 'Date' in df.columns:
        df['Date'] = pd.to_datetime(df['Date'], errors='coerce')
    df = df.dropna(subset=['Meter Reading','Household ID','Phase'])
    results = []
    for hh_id, grp in df.groupby('Household ID'):
        def get(phase):
            rows = grp[grp['Phase']==phase]
            if rows.empty: return None, None
            return rows['Meter Reading'].values[0], rows['Date'].values[0]
        bs_r, bs_d = get('Baseline Start')
        be_r, be_d = get('Baseline End')
        is_r, is_d = get('Intervention Start')
        ie_r, ie_d = get('Intervention End')
        row = {'Household ID': hh_id}
        if bs_r is not None and be_r is not None:
            days = max((pd.Timestamp(be_d) - pd.Timestamp(bs_d)).days, 1)
            row['baseline_daily_avg'] = round((be_r - bs_r) / days, 2)
        else:
            row['baseline_daily_avg'] = None
        if is_r is not None and ie_r is not None:
            days = max((pd.Timestamp(ie_d) - pd.Timestamp(is_d)).days, 1)
            row['intervention_daily_avg'] = round((ie_r - is_r) / days, 2)
        else:
            row['intervention_daily_avg'] = None
        if row['baseline_daily_avg'] and row['intervention_daily_avg']:
            row['efficiency_pct'] = round((row['baseline_daily_avg'] - row['intervention_daily_avg']) / row['baseline_daily_avg'] * 100, 1)
        else:
            row['efficiency_pct'] = None
        results.append(row)
    summary = pd.DataFrame(results)
    if not summary.empty and 'efficiency_pct' in summary.columns and summary['efficiency_pct'].notna().any():
        summary = summary.sort_values('efficiency_pct', ascending=False).reset_index(drop=True)
        summary['rank'] = range(1, len(summary)+1)
    return summary, df

