hh_summary, hh_clean = process_household(hh_raw)

def detect_phase():
    if not hh_clean.empty and 'Phase' in hh_clean.columns:
        phases = hh_clean['Phase'].dropna().unique()
        if any('Intervention' in p for p in phases): return "Household: Intervention"
        if any('Baseline' in p for p in phases):     return "Household: Baseline"
    if not sc_clean.empty and 'Phase' in sc_clean.columns:
        p = sc_clean['Phase'].dropna()
        if not p.empty: return f"School: {p.iloc[-1]}"
    return "Not started"

